from flask import Flask, request, jsonify, make_response
from datetime import datetime
import logging

app = Flask(__name__)
app.config['LOGGING'] = True
app.config['SECRET_KEY'] = 'your_secret_key'

log_format = '%(asctime)s %(levelname)s:%(name)s - %(message)s'
logging.basicConfig(filename='application.log', level=logging.INFO, format=log_format)

users = {
    'user1': {'password': 'hashed_password1', 'email': 'user1@example.com'},
    'user2': {'password': 'hashed_password2', 'email': 'user2@example.com'}
}

@app.route('/login', methods=['POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        user_ip = request.remote_addr
        user_agent = request.user_agent.toString()

        if username not in users or users[username]['password'] != password:
            logging.info(f'Login attempt by {username} failed (IP: {user_ip}, User Agent: {user_agent})')
            response = make_response(jsonify({"error": "Invalid username or password"}), 401)
        else:
            logging.info(f'Successful login by {username} (IP: {user_ip}, User Agent: {user_agent})')
            response = make_response(jsonify({"message": "Login successful"}), 200)

        response.headers['Access-Control-Allow-Origin'] = '*'
        return response

if __name__ == '__main__':
    app.run(debug=True)